"use client";

import { CheckIcon, CircleXIcon, CopyIcon } from "lucide-react";
import { motion } from "motion/react";
import type { ComponentProps } from "react";
import { Button } from "@/components/ui/button";
import type { CopyState } from "@/hooks/use-copy-to-clipboard";
import { useCopyToClipboard } from "@/hooks/use-copy-to-clipboard";
import { cn } from "@/lib/utils";
import {
	IconSwap,
	IconSwapItem,
} from "@/registry/components/icon-swap/icon-swap";

export type CopyStateIconProps = {
	state: CopyState;
	/** Custom icon for idle state. */
	idleIcon?: React.ReactNode;
	/** Custom icon for done state. */
	doneIcon?: React.ReactNode;
	/** Custom icon for error state. */
	errorIcon?: React.ReactNode;
};

export function CopyStateIcon({
	state,
	idleIcon,
	doneIcon,
	errorIcon,
}: CopyStateIconProps) {
	let icon = idleIcon ?? (
		<CopyIcon data-icon="inline-start" data-slot="idle-icon" />
	);

	if (state === "done") {
		icon = doneIcon ?? (
			<CheckIcon data-icon="inline-start" data-slot="done-icon" />
		);
	} else if (state === "error") {
		icon = errorIcon ?? (
			<CircleXIcon data-icon="inline-start" data-slot="error-icon" />
		);
	}

	return (
		<IconSwap>
			<IconSwapItem key={state} as={motion.span}>
				{icon}
			</IconSwapItem>
		</IconSwap>
	);
}

export type CopyButtonProps = ComponentProps<typeof Button> & {
	/** The text to copy, or a function that returns the text. */
	text: string | (() => string);
	/** Called with the copied text on successful copy. */
	onCopySuccess?: (text: string) => void;
	/** Called with the error if the copy operation fails. */
	onCopyError?: (error: Error) => void;
} & Omit<CopyStateIconProps, "state">;

export function CopyButton({
	className,
	size = "icon",
	children,
	text,
	idleIcon,
	doneIcon,
	errorIcon,
	onClick,
	onCopySuccess,
	onCopyError,
	...props
}: CopyButtonProps) {
	const { state, copy } = useCopyToClipboard({
		onCopySuccess,
		onCopyError,
	});

	return (
		<Button
			className={cn("will-change-transform", className)}
			size={size}
			onClick={(e) => {
				void copy(text);
				onClick?.(e);
			}}
			aria-label="Copy"
			{...props}
		>
			<CopyStateIcon
				state={state}
				idleIcon={idleIcon}
				doneIcon={doneIcon}
				errorIcon={errorIcon}
			/>
			{children}
		</Button>
	);
}

export default CopyButton;

"use client";

import type { AnimatePresenceProps, HTMLMotionProps } from "motion/react";
import { AnimatePresence, motion } from "motion/react";

export function IconSwap(props: React.PropsWithChildren<AnimatePresenceProps>) {
	return <AnimatePresence mode="popLayout" initial={false} {...props} />;
}

type MotionElement = typeof motion.div | typeof motion.span;

export function IconSwapItem({
	as: Component = motion.div,
	...props
}: HTMLMotionProps<"div"> & {
	as?: MotionElement;
}) {
	return (
		<Component
			initial={{ opacity: 0, scale: 0.25, filter: "blur(4px)" }}
			animate={{ opacity: 1, scale: 1, filter: "blur(0px)" }}
			exit={{ opacity: 0, scale: 0.25, filter: "blur(4px)" }}
			transition={{
				type: "spring",
				duration: 0.3,
				bounce: 0,
			}}
			{...props}
		/>
	);
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

export type CopyState = "idle" | "done" | "error";

export type UseCopyToClipboardOptions = {
	onCopySuccess?: (text: string) => void;
	onCopyError?: (error: Error) => void;
	resetDelay?: number;
};

export function useCopyToClipboard({
	onCopySuccess,
	onCopyError,
	resetDelay = 1500,
}: UseCopyToClipboardOptions = {}) {
	const [state, setState] = useState<CopyState>("idle");
	const resetTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

	useEffect(() => {
		return () => {
			if (resetTimeoutRef.current) {
				clearTimeout(resetTimeoutRef.current);
			}
		};
	}, []);

	const copy = useCallback(
		async (text: string | (() => string)) => {
			// Clear any pending reset
			if (resetTimeoutRef.current) {
				clearTimeout(resetTimeoutRef.current);
			}

			try {
				const finalText = typeof text === "function" ? text() : text;
				await navigator.clipboard.writeText(finalText);

				setState("done");

				onCopySuccess?.(finalText);
			} catch (error) {
				setState("error");

				onCopyError?.(
					error instanceof Error ? error : new Error("Copy failed"),
				);
			} finally {
				// Schedule reset to idle
				resetTimeoutRef.current = setTimeout(() => {
					setState("idle");
				}, resetDelay);
			}
		},
		[onCopySuccess, onCopyError, resetDelay],
	);

	return { state, copy } as const;
}
